"use client";

import { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Input } from "@heroui/input";
import { Button } from "@heroui/button";
import { ChatMessage } from "@/types/chat";
import { ChatAPI } from "@/lib/chatApi";
import { v4 as uuidv4 } from "uuid";

interface ChatComponentProps {
  className?: string;
  conversationId?: string;
}

export default function ChatComponent({
                                        className = "",
                                        conversationId: initialConversationId
                                      }: ChatComponentProps) {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [inputValue, setInputValue] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [conversationId, setConversationId] = useState(
    initialConversationId || uuidv4()
  );
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Auto-scroll to bottom when messages change
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!inputValue.trim()) return;

    // Add user message to chat
    const userMessage: ChatMessage = {
      id: uuidv4(),
      content: inputValue,
      role: "user",
      timestamp: new Date()
    };

    setMessages((prev) => [...prev, userMessage]);
    setInputValue("");
    setIsLoading(true);
    setError(null);

    try {
      // Add loading placeholder
      const assistantMessage: ChatMessage = {
        id: uuidv4(),
        content: "",
        role: "assistant",
        timestamp: new Date()
      };

      setMessages((prev) => [...prev, assistantMessage]);

      // Send message to API
      await ChatAPI.sendMessageStream(
        {
          message: inputValue,
          conversationId
        },
        (chunk) => {
          // Update the last assistant message with streaming content
          setMessages((prev) => {
            const newMessages = [...prev];
            const lastMessage = newMessages[newMessages.length - 1];
            if (lastMessage.role === "assistant") {
              lastMessage.content += chunk;
            }
            return newMessages;
          });
        },
        () => {
          setIsLoading(false);
          inputRef.current?.focus();
        },
        (error) => {
          setError(error.message);
          setIsLoading(false);
          // Remove the placeholder message if there's an error
          setMessages((prev) => prev.slice(0, -1));
        }
      );
    } catch (err) {
      const errorMessage =
        err instanceof Error ? err.message : "Failed to send message";
      setError(errorMessage);
      setIsLoading(false);
      // Remove the placeholder message
      setMessages((prev) => prev.slice(0, -1));
    }
  };

  const handleClearChat = () => {
    setMessages([]);
    setConversationId(uuidv4());
    setError(null);
    inputRef.current?.focus();
  };

  return (
    <div
      className={`flex flex-col h-full bg-gradient-to-b from-slate-900 to-black rounded-lg overflow-hidden ${className}`}>
      {/* Header */}
      <div className="bg-gradient-to-r from-purple-600 to-blue-600 p-4 shadow-lg">
        <div className="flex justify-between items-center">
          <h2 className="text-white font-bold text-lg">AI Chat</h2>
          <Button
            isIconOnly
            variant="light"
            className="text-white hover:bg-white/20"
            onClick={handleClearChat}
            size="sm"
          >
            ✕
          </Button>
        </div>
      </div>

      {/* Messages Container */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-900/30">
        <AnimatePresence>
          {messages.length === 0 ? (
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
              className="h-full flex items-center justify-center text-center"
            >
              <div className="text-slate-400">
                <p className="text-lg mb-2">Start a conversation</p>
                <p className="text-sm">Ask me anything!</p>
              </div>
            </motion.div>
          ) : (
            messages.map((message, index) => (
              <motion.div
                key={message.id}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                transition={{ duration: 0.3 }}
                className={`flex ${
                  message.role === "user" ? "justify-end" : "justify-start"
                }`}
              >
                <div
                  className={`max-w-xs lg:max-w-md xl:max-w-lg px-4 py-2 rounded-lg ${
                    message.role === "user"
                      ? "bg-blue-600 text-white rounded-br-none"
                      : "bg-slate-700 text-slate-100 rounded-bl-none"
                  }`}
                >
                  <p className="text-sm break-words whitespace-pre-wrap">
                    {message.content}
                    {message.role === "assistant" &&
                      isLoading &&
                      index === messages.length - 1 && (
                        <span className="inline-block ml-1 animate-pulse">▌</span>
                      )}
                  </p>
                  <p className="text-xs opacity-70 mt-1">
                    {message.timestamp.toLocaleTimeString([], {
                      hour: "2-digit",
                      minute: "2-digit"
                    })}
                  </p>
                </div>
              </motion.div>
            ))
          )}
        </AnimatePresence>

        {error && (
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className="bg-red-900/30 border border-red-600 text-red-200 px-4 py-3 rounded-lg"
          >
            <p className="text-sm">{error}</p>
          </motion.div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="border-t border-slate-700 p-4 bg-slate-900/50">
        <form onSubmit={handleSendMessage} className="space-y-2">
          <Input
            ref={inputRef}
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            placeholder="Type your message..."
            disabled={isLoading}
            className="text-white"
            endContent={
              <Button
                isIconOnly
                type="submit"
                disabled={isLoading || !inputValue.trim()}
                className="bg-blue-600 hover:bg-blue-700 text-white"
              >
                {isLoading ? "⏳" : "→"}
              </Button>
            }
          />
        </form>
        {isLoading && (
          <motion.p
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="text-xs text-slate-400 mt-2"
          >
            AI is thinking...
          </motion.p>
        )}
      </div>
    </div>
  );
}

